import{_ as e,o as t,c as o,ag as n}from"./chunks/framework.BBBcTwIo.js";const h=JSON.parse('{"title":"Capture invocation payloads","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/payload-capture.md","filePath":"how-to/payload-capture.md"}'),i={name:"how-to/payload-capture.md"};function s(r,a,l,p,d,c){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="capture-invocation-payloads" tabindex="-1">Capture invocation payloads <a class="header-anchor" href="#capture-invocation-payloads" aria-label="Permalink to &quot;Capture invocation payloads&quot;">​</a></h1><p><strong>Goal:</strong> See <strong>argument values</strong> on <strong>INVOKE</strong> rows in the Event Monitor log.</p><p><strong>Prerequisites:</strong> Event Monitor installed; Play Mode; ILPP instrumentation active for the invocation site (or manual tagging — below).</p><h2 id="enable-payload-capture" tabindex="-1">Enable payload capture <a class="header-anchor" href="#enable-payload-capture" aria-label="Permalink to &quot;Enable payload capture&quot;">​</a></h2><ol><li>Open <strong>Window → Event Monitor</strong>.</li><li>Toggle <strong>Payload</strong> (toolbar) <strong>on</strong>.</li></ol><p>When enabled, the IL-instrumented path can record invocation parameters into the ring buffer. Zero-argument events still appear; the UI distinguishes <strong>no args</strong> from untagged payloads.</p><div class="warning custom-block"><p class="custom-block-title">Performance and safety</p><p>Payload capture increases <strong>allocations</strong> (including boxing for value types) and <strong>log size</strong>. Keep it off during normal profiling unless you need arguments. <strong>Payload Details</strong> (reflection) is heavier still — use only for focused debugging.</p></div><h2 id="optional-tagpayload-before-firing" tabindex="-1">Optional: <code>TagPayload</code> before firing <a class="header-anchor" href="#optional-tagpayload-before-firing" aria-label="Permalink to &quot;Optional: `TagPayload` before firing&quot;">​</a></h2><p>For patterns <strong>not</strong> covered by automatic injection, or when you need explicit control, call <code>EventBus.TagPayload(...)</code> <strong>immediately before</strong> invoking the event:</p><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">EventBus.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">TagPayload</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(damage, remainingHp, source);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OnDamaged</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Invoke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(damage, remainingHp, source);</span></span></code></pre></div><p>Tagging is respected when payload capture is enabled and recording is on.</p><h2 id="payload-details-reflection" tabindex="-1">Payload details (reflection) <a class="header-anchor" href="#payload-details-reflection" aria-label="Permalink to &quot;Payload details (reflection)&quot;">​</a></h2><p>Enable <strong>Payload Details</strong> to inspect public fields/properties on payload objects (with safe limits: item count, depth, cycle detection). Use sparingly.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../reference/il-limitations.html">IL patterns and limitations</a></li><li><a href="./../reference/event-bus-api.html">EventBus API</a></li></ul>',15)])])}const u=e(i,[["render",s]]);export{h as __pageData,u as default};
